use std::fmt::{self, Debug};

struct SecretData { 
    value: Vec<u8>
}
impl Debug for SecretData { 
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "SecretData({:?})", self.value)
    }
}

trait Encryptable { 
    fn check_integrity(&self) -> bool;
}
impl Encryptable for SecretData { 
    fn check_integrity(&self) -> bool {
        !self.value.is_empty()
    }
}

fn process_key_material(data: Vec<u8>) -> Box<dyn Debug + Send> {
    let secret = SecretData { value: data };
    Box::new(secret)
}

fn perform_crypto_operation() -> impl Encryptable {
    SecretData { value: vec![0xde, 0xad, 0xbe, 0xef] }
}

fn main() {
    let key_material = process_key_material(vec![1, 2, 3]);
    println!("Processed material debug: {:?}", key_material);

    let operation = perform_crypto_operation();
    if operation.check_integrity() {
        println!("Operation successfully initialized with valid keys.");
    }
}

