use std::error::Error;

struct Point { x: f64, y: f64 } 

trait PathResult {
    fn calculate_distance(self) -> f64;
}

struct StraightPath { point: Point }
impl PathResult for StraightPath {
    fn calculate_distance(self) -> f64 {
        f64::sqrt((self.point.x - 10.0).powi(2) + (self.point.y - 5.0).powi(2))
    }
}

struct CurvedPath { start: Point, end: Point }
impl PathResult for CurvedPath {
    fn calculate_distance(self) -> f64 {
        ((self.start.x - self.end.x).powi(2) + (self.start.y - self.end.y).powi(2)).sqrt() * 1.5
    }
}

fn find_optimal_path<T: PathResult>(result_type: T) -> f64 {
    result_type.calculate_distance()
}

fn main() -> Result<(), Box<dyn Error>> {
    let straight = StraightPath { point: Point { x: 1.0, y: 2.0 } };
    let curved = CurvedPath { start: Point { x: 3.0, y: 4.0 }, end: Point { x: 7.0, y: 8.0 } };

    let dist_s = find_optimal_path(straight);
    println!("Straight Path Distance: {}", dist_s);

    let dist_c = find_optimal_path(curved);
    println!("Curved Path Distance: {}", dist_c);

    Ok(())
}

use std::fmt::Debug;

trait CollidableBody<T> {
    fn calculate_force(&self) -> T;
}

struct Sphere { 
    radius: f32,
    mass: f32,
}

impl CollidableBody<f32> for Sphere {
    fn calculate_force(&self) -> f32 {
        2.0 * 3.14159 * self.radius * self.mass
    }
}

struct Cube { 
    side: f32,
    density: f32,
}

impl CollidableBody<f32> for Cube {
    fn calculate_force(&self) -> f32 {
        6.0 * self.side * self.side * self.density
    }
}

fn process_collision_result() -> Box<dyn CollidableBody<f32>> {
    let sphere = Sphere { radius: 1.0, mass: 5.0 };
    Box::new(sphere)
}

fn main() {
    let body = process_collision_result();
    let force = body.calculate_force();
    println!("Calculated collision force: {}", force);
}

use std::io::{self, BufReader, Read};
use std::fs::File;

struct TextProcessor {
    reader: BufReader<File>,
}

impl TextProcessor {
    fn new(path: &str) -> io::Result<Self> {
        let file = File::open(path)?;
        Ok(TextProcessor { reader: BufReader::new(file) })
    }

    fn process_stream(&mut self, pattern: &str) -> io::Result<String> {
        let mut content = String::new();
        self.reader.read_to_string(&mut content)?;

        let lines: Vec<&str> = content.lines().collect();
        let filtered: Vec<&str> = lines.iter()
            .filter(|&line| line.contains(pattern))
            .map(|&s| s)
            .collect();

        Ok(filtered.join("n"))
    }
}

fn main() -> io::Result<()> {
    let mut processor = TextProcessor::new("data.txt")?;
    let result = processor.process_stream("error")?;
    println!("Filtered content:n---n{}
---", result);
    Ok(())
}
